$scripts = @(
	{
		Set-ItemProperty -LiteralPath 'Registry::HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Winlogon' -Name 'AutoLogonCount' -Type 'DWord' -Force -Value 0;
	};
	{
		@(
			Get-ChildItem -LiteralPath 'C:\' -Force;
			Get-ChildItem -LiteralPath 'C:\Users' -Force;
			Get-ChildItem -LiteralPath 'C:\Users\Default' -Force -Recurse -Depth 2;
			Get-ChildItem -LiteralPath 'C:\Users\Public' -Force -Recurse -Depth 2;
			Get-ChildItem -LiteralPath 'C:\ProgramData' -Force;
		) | Where-Object -FilterScript {
			$_.Attributes.HasFlag( [System.IO.FileAttributes]::ReparsePoint );
		} | Remove-Item -Force -Recurse -Verbose;
	};
	{
		cmd.exe /c "rmdir C:\Windows.old";
	};
	{
		try {
			Start-Transcript -Path 'C:\Windows\Setup\Scripts\BitLocker.log' -Append;
			if ((Get-BitLockerVolume -MountPoint 'C:' -ErrorAction SilentlyContinue).ProtectionStatus -eq 'On') {
				'BitLocker already on; skipping.';
				return;
			}
			Enable-BitLocker -MountPoint 'C:' -EncryptionMethod XtsAes256 -UsedSpaceOnly -TpmProtector -SkipHardwareTest -ErrorAction Stop | Out-Null;
			Add-BitLockerKeyProtector -MountPoint 'C:' -RecoveryPasswordProtector -ErrorAction Stop | Out-Null;
			$rp = (Get-BitLockerVolume -MountPoint 'C:').KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' } | Select-Object -First 1;
			$line = "=== BitLocker Recovery Key ===`nHost:  $(hostname)`nWhen:  $(Get-Date -Format 'o')`nID:    $($rp.KeyProtectorId)`nKey:   $($rp.RecoveryPassword)`n================================";
			# Recovery key written ONLY to C:\Windows\Setup\Scripts\BitLocker-Recovery.txt
			# (on the BitLocker-encrypted volume itself — self-protecting). The prior
			# "also write to Ventoy" branch was removed: under the no-USB workflow Ventoy
			# lives on the internal Netac SSD, so a Ventoy-data copy of the key is a
			# permanent unencrypted copy inside the machine, which defeats BitLocker.
			# The first-login scheduled task (below) displays this file, requires the
			# user to type-back the key to confirm Bitwarden save, then deletes it.
			$line | Out-File -FilePath 'C:\Windows\Setup\Scripts\BitLocker-Recovery.txt' -Encoding UTF8;
			"Recovery key staged at C:\Windows\Setup\Scripts\BitLocker-Recovery.txt. Will be shown + deleted at tom's first logon.";
		} catch {
			"BitLocker setup failed: $_";
		} finally { Stop-Transcript }
	};
	{
		$ventoy = Get-Volume | Where-Object { $_.FileSystemLabel -eq 'Ventoy' -and $_.DriveLetter } | Select-Object -First 1;
		if ($ventoy) {
			$src = "$($ventoy.DriveLetter):\phase-1-windows\winget-import.json";
			if (Test-Path -LiteralPath $src) {
				New-Item -ItemType Directory -Force -Path 'C:\Windows\Setup\Scripts' | Out-Null;
				Copy-Item -LiteralPath $src -Destination 'C:\Windows\Setup\Scripts\winget-import.json' -Force;
				'Staged winget-import.json from Ventoy USB.';
			}
		}
	};
	{
		$importPath = 'C:\Windows\Setup\Scripts\winget-import.json';
		$runnerPath = 'C:\Windows\Setup\Scripts\WingetImport.ps1';
		if (-not (Test-Path -LiteralPath $importPath)) {
			'No winget-import.json staged; skipping scheduled-task registration.';
			return;
		}
		$runner = @'
$ErrorActionPreference = "Continue";
$log = "C:\Windows\Setup\Scripts\WingetImport.log";
Start-Transcript -Path $log -Append;
try {
	$deadline = (Get-Date).AddMinutes(20);
	do {
		try { $online = Test-Connection -ComputerName "cdn.winget.microsoft.com" -Count 1 -Quiet -ErrorAction SilentlyContinue } catch { $online = $false }
		if (-not $online) { Start-Sleep -Seconds 15 }
	} while (-not $online -and (Get-Date) -lt $deadline);
	if (-not $online) { "No network after 20 min; aborting. Task remains scheduled for next logon."; return }
	winget.exe import --import-file "C:\Windows\Setup\Scripts\winget-import.json" --accept-package-agreements --accept-source-agreements --ignore-versions;
	if ($LASTEXITCODE -eq 0) {
		schtasks.exe /Delete /TN "WingetImportOnce" /F;
		Remove-Item "C:\Windows\Setup\Scripts\winget-import.json" -Force -ErrorAction SilentlyContinue;
		"Winget import succeeded; task self-deleted.";
	} else {
		"winget import exited $LASTEXITCODE. Task remains scheduled for retry.";
	}
} finally { Stop-Transcript }
'@;
		Set-Content -LiteralPath $runnerPath -Value $runner -Encoding UTF8;
		$action = "powershell.exe -NoProfile -WindowStyle Hidden -ExecutionPolicy Bypass -File `"$runnerPath`"";
		schtasks.exe /Create /TN 'WingetImportOnce' /SC ONLOGON /RU 'Tom' /DELAY 0002:00 /RL HIGHEST /TR $action /F;
		'Registered WingetImportOnce scheduled task (fires 2 min after Tom logon).';
	};
	{
		# First-login BitLocker recovery-key confirmation. Displays the key,
		# requires the user to type it back to confirm Bitwarden save, then
		# deletes C:\Windows\Setup\Scripts\BitLocker-Recovery.txt. Task stays
		# registered across logons until the user completes the type-back,
		# so a cancelled dialog just pops up again next logon.
		$keyFile = 'C:\Windows\Setup\Scripts\BitLocker-Recovery.txt';
		if (-not (Test-Path -LiteralPath $keyFile)) {
			'No BitLocker recovery file; skipping MetisBitLockerConfirm registration.';
			return;
		}
		$runnerPath = 'C:\Windows\Setup\Scripts\MetisBitLockerConfirm.ps1';
		$runner = @'
$ErrorActionPreference = "Stop";
$keyFile = "C:\Windows\Setup\Scripts\BitLocker-Recovery.txt";
$log = "C:\Windows\Setup\Scripts\MetisBitLockerConfirm.log";
Start-Transcript -Path $log -Append;
try {
	if (-not (Test-Path -LiteralPath $keyFile)) {
		"Key file absent; self-deleting task.";
		schtasks.exe /Delete /TN "MetisBitLockerConfirm" /F;
		return;
	}
	$content = Get-Content -LiteralPath $keyFile -Raw;
	$key = (($content -split "`n" | Where-Object { $_ -match "^Key:" }) -replace "^Key:\s*","" -replace "`r","").Trim();
	if (-not $key) {
		"Could not extract Key: line; leaving task registered.";
		return;
	}
	Add-Type -AssemblyName PresentationFramework;
	Add-Type -AssemblyName Microsoft.VisualBasic;
	$showMsg = "Your BitLocker recovery key is:`n`n    $key`n`nSave this to Bitwarden NOW as 'Metis BitLocker'.`n`nAfter you click OK, you'll re-type the key to confirm. If it matches exactly, the on-disk copy is deleted and Bitwarden becomes your only copy. If you Cancel, this dialog returns at next logon.";
	[System.Windows.MessageBox]::Show($showMsg, "Metis BitLocker Recovery Key", "OK", "Warning") | Out-Null;
	while ($true) {
		$typed = [Microsoft.VisualBasic.Interaction]::InputBox("Re-type the 48-digit recovery key exactly (8 groups of 6 digits, dash-separated).`n`nLeave blank or Cancel to defer until next logon.", "Metis — confirm Bitwarden save");
		$typed = $typed.Trim();
		if (-not $typed) { "User deferred."; return; }
		if ($typed -eq $key) {
			[System.Windows.MessageBox]::Show("Confirmed. Deleting on-disk copy. Bitwarden is now the only copy.", "Metis", "OK", "Information") | Out-Null;
			Remove-Item -LiteralPath $keyFile -Force;
			schtasks.exe /Delete /TN "MetisBitLockerConfirm" /F;
			"Confirmed + file deleted + task self-deleted.";
			return;
		}
		[System.Windows.MessageBox]::Show("Didn't match. Try again.", "Metis", "OK", "Error") | Out-Null;
	}
} finally { Stop-Transcript }
'@;
		Set-Content -LiteralPath $runnerPath -Value $runner -Encoding UTF8;
		$action = "powershell.exe -NoProfile -WindowStyle Hidden -ExecutionPolicy Bypass -File `"$runnerPath`"";
		schtasks.exe /Create /TN 'MetisBitLockerConfirm' /SC ONLOGON /RU 'Tom' /DELAY 0001:00 /RL HIGHEST /TR $action /F;
		'Registered MetisBitLockerConfirm scheduled task (fires 1 min after Tom logon).';
	};
);

& {
  [float] $complete = 0;
  [float] $increment = 100 / $scripts.Count;
  foreach( $script in $scripts ) {
    Write-Progress -Id 0 -Activity 'Running scripts to finalize your Windows installation. Do not close this window.' -PercentComplete $complete;
    '*** Will now execute command «{0}».' -f $(
      $script.ToString().Trim() -replace '\s+', ' ' -replace '^(.{99})(.+)$', '$1…';
    );
    $start = [datetime]::Now;
    & $script;
    '*** Finished executing command after {0:0} ms.' -f [datetime]::Now.Subtract( $start ).TotalMilliseconds;
    "`r`n" * 3;
    $complete += $increment;
  }
} *>&1 | Out-String -Width 1KB -Stream >> "C:\Windows\Setup\Scripts\FirstLogon.log";
